// Example of using Web Speech API for narration in CurioShorts
function generateNarration(text) {
  const utterance = new SpeechSynthesisUtterance(text);
  utterance.rate = 1.0;
  utterance.pitch = 1.0;
  utterance.voice = speechSynthesis.getVoices().find(v => v.lang === 'en-US');
  speechSynthesis.speak(utterance);
}

// Usage during video generation
const lyrics = ["What is photosynthesis?", "It's how plants make their food!"];
lyrics.forEach(line => generateNarration(line));

CurioShorts uses IndexedDB to persist generated shorts locally. This allows users to save and access their creations without relying on server storage. Example implementation:
javascript
// Saving a generated short to IndexedDB
async function saveShort(shortId, data) {
  const request = indexedDB.open('CurioShorts', 1);
  request.onupgradeneeded = (event) => {
    const db = event.target.result;
    db.createObjectStore('shorts', { keyPath: 'id' });
  };
  request.onsuccess = (event) => {
    const db = event.target.result;
    const transaction = db.transaction('shorts', 'readwrite');
    transaction.objectStore('shorts').put(data);
  };
}
